start.filterFormula:
OR(
    /* Scenario 1: The Max of the 3 enrichment fields is greater than the current value */
    BLANKVALUE({!$Record.Gemini_Employee_Count__c}, 0) > BLANKVALUE({!$Record.NumberOfEmployees}, 0),
    BLANKVALUE({!$Record.Clay_Employee_Count__c}, 0) > BLANKVALUE({!$Record.NumberOfEmployees}, 0),
    BLANKVALUE({!$Record.Clay_HQ_Employees__c}, 0)   > BLANKVALUE({!$Record.NumberOfEmployees}, 0),

    /* Scenario 2: Current value is blank, but we have data in at least one enrichment field */
    AND(
        ISBLANK({!$Record.NumberOfEmployees}),
        OR(
            NOT(ISBLANK({!$Record.Gemini_Employee_Count__c})),
            NOT(ISBLANK({!$Record.Clay_Employee_Count__c})),
            NOT(ISBLANK({!$Record.Clay_HQ_Employees__c}))
        )
    )
)

OR(
	AND(
		ISNEW(),
		NOT(ISBLANK({!$Record.ContactId}))
		),
	AND(
		NOT(ISBLANK({!$Record.ContactId})),
              ISBLANK({!$Record__Prior.ContactId})
 )

	)

OR(
	AND(
		NOT(INCLUDES({!$Record__Prior.Contact_Flags__c}, "Customer Security Contact")),
		INCLUDES({!$Record.Contact_Flags__c}, "Customer Security Contact")
		),
	AND(
		NOT(INCLUDES({!$Record.Contact_Flags__c}, "Customer Security Contact")),
		INCLUDES({!$Record__Prior.Contact_Flags__c}, "Customer Security Contact")
		)
	)

