":axonify: " & 
IF(
    /* Scenario 1: Both exist AND are different people */
    AND(
        NOT(ISBLANK({!$Record.Opportunity_CSM__c})), 
        NOT(ISBLANK({!$Record.Opportunity_AM__c})),
        {!$Record.Opportunity_CSM__c} <> {!$Record.Opportunity_AM__c}
    ),
    {!$Record.Opportunity_CSM__r.Full_Name__c} & " and " & {!$Record.Opportunity_AM__r.Full_Name__c},

    IF(
        /* Scenario 2: Only CSM exists (OR CSM and AM are the same person) */
        NOT(ISBLANK({!$Record.Opportunity_CSM__c})),
        {!$Record.Opportunity_CSM__r.Full_Name__c},

        IF(
            /* Scenario 3: Only AM exists */
            NOT(ISBLANK({!$Record.Opportunity_AM__c})),
            {!$Record.Opportunity_AM__r.Full_Name__c},

            /* Scenario 4: Both are blank - Fallback to Record Owner */
            {!$Record.Owner.Full_Name__c}
        )
    )
) & 
" just landed an expansion with " & {!$Record.Account.Name} & 
" on a " & TEXT({!$Record.Duration__c}) & " month contract for $" & 
TEXT({!$Record.New_ARR__c}) & " Annual Recurring Revenue! :tada:"

